module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output red
);

    // Internal logic
    reg [7:0] green_counter;
    reg [7:0] yellow_counter;
    reg [7:0] red_counter;
    reg [1:0] state;

    // State definitions
    localparam GREEN = 2'b00;
    localparam YELLOW = 2'b01;
    localparam RED = 2'b10;

    // Output signals
    reg red_reg;
    reg yellow_reg;
    reg green_reg;

    // Assign output signals
    assign red = red_reg;
    assign clock = (green_counter + yellow_counter + red_counter);

    // Always block for state machine and counters
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            green_counter <= 8'd60;
            yellow_counter <= 8'd5;
            red_counter <= 8'd10;
            state <= GREEN;
            red_reg <= 1'b0;
            yellow_reg <= 1'b0;
            green_reg <= 1'b1;
        end else begin
            case (state)
                GREEN: begin
                    if (green_counter > 0) begin
                        green_counter <= green_counter - 1;
                    end else begin
                        green_counter <= 8'd60;
                        state <= YELLOW;
                        red_reg <= 1'b0;
                        yellow_reg <= 1'b1;
                        green_reg <= 1'b0;
                    end
                end
                YELLOW: begin
                    if (yellow_counter > 0) begin
                        yellow_counter <= yellow_counter - 1;
                    end else begin
                        yellow_counter <= 8'd5;
                        state <= RED;
                        red_reg <= 1'b1;
                        yellow_reg <= 1'b0;
                        green_reg <= 1'b0;
                    end
                end
                RED: begin
                    if (red_counter > 0) begin
                        red_counter <= red_counter - 1;
                    end else begin
                        red_counter <= 8'd10;
                        state <= GREEN;
                        red_reg <= 1'b0;
                        yellow_reg <= 1'b0;
                        green_reg <= 1'b1;
                    end
                end
                default: begin
                    green_counter <= 8'd60;
                    yellow_counter <= 8'd5;
                    red_counter <= 8'd10;
                    state <= GREEN;
                    red_reg <= 1'b0;
                    yellow_reg <= 1'b0;
                    green_reg <= 1'b1;
                end
            endcase

            // Handle pedestrian button press
            if (pass_request && (green_counter > 10)) begin
                green_counter <= 10;
            end
        end
    end

endmodule
